// Promise chain — nested-ish
function loadUserChain(userId) {
  return fetch('/api/users/' + userId)
    .then(function(r) { return r.json(); })
    .then(function(user) {
      return fetch('/api/posts?userId=' + user.id);
    })
    .then(function(r) { return r.json(); });
}

// Async/await — looks synchronous
async function loadUserAsync(userId) {
  const userRes = await fetch('/api/users/' + userId);
  const user = await userRes.json();

  const postsRes = await fetch('/api/posts?userId=' + user.id);
  const posts = await postsRes.json();

  return { user, posts };
}

loadUserAsync(1).then(function(data) {
  console.log(data.user.name, 'has', data.posts.length, 'posts');
});

async function loadDashboard() {
  // BAD — sequential (slow):
  // const user = await fetch('/api/user').then(r => r.json());
  // const posts = await fetch('/api/posts').then(r => r.json());
  // Total time: time(user) + time(posts)

  // GOOD — parallel (fast):
  const [user, posts] = await Promise.all([
    fetch('/api/user').then(function(r) { return r.json(); }),
    fetch('/api/posts').then(function(r) { return r.json(); })
  ]);
  // Total time: max(time(user), time(posts))

  return { user, posts };
}

loadDashboard().then(function(d) {
  console.log('Dashboard loaded:', d.user.name, d.posts.length, 'posts');
});

async function saveUserData(user) {
  try {
    const response = await fetch('/api/users', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(user)
    });

    if (!response.ok) {
      throw new Error('HTTP error: ' + response.status);
    }

    const saved = await response.json();
    return saved;
  } catch (err) {
    // Catches both network errors AND HTTP errors
    console.error('Save failed:', err.message);

